import { Component, h, Prop, Event, EventEmitter, Listen, Fragment } from '@stencil/core';
import { ContextMenuItem } from './mx-context-menu.model';
import { DomHandler } from '@src/utils/mx-utils/domhandler';
import { KeyboardCodes } from '@src/utils/mx-utils/Events';
import { isNullOrUndefined } from '@src/utils/mx-utils/utils';

@Component({
  tag: 'mx-context-menu',
  styleUrl: 'mx-context-menu.css'
})
export class MxContextMenu {
  /** Sets the list of items in context menu. */
  @Prop() readonly model: ContextMenuItem[];

  /** Attaches context menu event listener to entire document when true. */
  @Prop() readonly global: boolean = false;

  /** Attaches context menu event listeners to specified target. */
  @Prop() readonly target: HTMLElement;

  /** Attach styles to context menu via class names. */
  @Prop() readonly styleClass: string;

  /** Automatically calculates context menu z-index. */
  @Prop() readonly autoZIndex: boolean = true;

  /** Sets the z-index value of the context menu manually. */
  @Prop() readonly baseZIndex: number = 0;

  /** String or strings of events to listen for to show context menu. */
  @Prop() readonly triggerEvent: string | string[] = 'contextmenu';

  /** Event to attach listener to when context menu opens. */
  @Event() showEvent: EventEmitter<string>;

  /** Event to attach listener to when context menu closes. */
  @Event() hideEvent: EventEmitter<string>;

  private isGlobalMenu = false;
  private containerRef: HTMLElement;

  componentWillLoad() {
    this.isGlobalMenu = this.isGlobalRightClickMenu();
    if (this.global) {
      this.pushEventListeners('body');
    } else if (!isNullOrUndefined(this.target)) {
      this.pushEventListeners(this.target);
    }
  }

  @Listen('click', { target: 'document', capture: true })
  documentClickListener(event: MouseEvent) {
    if (this.containerRef.offsetParent && event.button !== 2) {
      this.hide();
    }
  }

  @Listen('keypress', { target: 'document', capture: true })
  documentKeypressListener(event: KeyboardEvent) {
    if (event.code === KeyboardCodes.ESCAPE) {
      this.hide();
    }
  }

  @Listen('resize', { target: 'window', capture: true })
  windowResizeListener() {
    if (!isNullOrUndefined(this.containerRef.offsetParent)) {
      this.hide();
    }
  }

  private getWidthHeight() {
    if (isNullOrUndefined(this.containerRef.offsetParent)) {
      const width = DomHandler.getHiddenElementOuterWidth(this.containerRef);
      const height = DomHandler.getHiddenElementOuterHeight(this.containerRef);
      return { width, height };
    } else {
      const width = this.containerRef.offsetWidth;
      const height = this.containerRef.offsetHeight;
      return { width, height };
    }
  }

  private updatePosition(event?: MouseEvent) {
    if (!isNullOrUndefined(event)) {
      let left = event.pageX + 1;
      let top = event.pageY + 1;
      const { width, height } = this.getWidthHeight();

      const viewport = DomHandler.getViewport();

      // flip
      if (left + width - DomHandler.getWindowScrollLeft() > viewport.width) {
        left -= width;
      }

      if (top + height - DomHandler.getWindowScrollTop() > viewport.height) {
        top -= height;
      }

      // fit
      if (left < DomHandler.getWindowScrollLeft()) {
        left = DomHandler.getWindowScrollLeft();
      }
      if (top < DomHandler.getWindowScrollTop()) {
        top = DomHandler.getWindowScrollTop();
      }

      this.containerRef.setAttribute('style', `left: ${left}px; top: ${top}px`);
    }
  }

  private moveOnTop() {
    if (this.autoZIndex) {
      this.containerRef.style.zIndex = String(this.baseZIndex + ++DomHandler.zIndex);
    }
  }

  private hide() {
    this.containerRef.style.display = 'none';
    this.hideEvent.emit();
  }

  private show(event: MouseEvent, hasTarget = false) {
    if (hasTarget) {
      this.updatePosition(event);
    }
    this.moveOnTop();
    this.containerRef.style.display = 'block';
    event.preventDefault();
    this.showEvent.emit();
  }

  private pushEventListeners(target) {
    if (typeof this.triggerEvent === 'string') {
      document.querySelector(target).addEventListener(this.triggerEvent, (event: MouseEvent) => {
        this.show(event, true);
      });
    } else {
      this.triggerEvent.forEach((ev) => {
        target.addEventListener(ev, (event: MouseEvent) => {
          this.show(event, false);
        });
      });
    }
  }

  private isGlobalRightClickMenu() {
    return this.global && (this.triggerEvent === 'contextmenu' || this.triggerEvent.includes('contextmenu'));
  }

  private triggerItemCommand(event: MouseEvent | KeyboardEvent, item: ContextMenuItem) {
    if (item.disabled || this.shouldTriggerCommand(event)) {
      event.preventDefault();
      return;
    }

    if (!isNullOrUndefined(item.url)) {
      event.preventDefault();
    }

    if (!isNullOrUndefined(item.command)) {
      item.command({
        originalEvent: event,
        item
      });
    }
  }

  private shouldTriggerCommand(event) {
    return (
      event.type !== 'click' &&
      (event.type !== 'keypress' || (event.code !== KeyboardCodes.ENTER && event.code !== KeyboardCodes.SPACE))
    );
  }

  private getTabIndex(item: ContextMenuItem) {
    if (item.disabled) {
      return -1;
    }
    return isNullOrUndefined(item.tabindex) ? '0' : item.tabindex;
  }

  private unbindListeners(target) {
    if (typeof this.triggerEvent === 'string') {
      document.querySelector(target).removeEventListener(this.triggerEvent, (event: MouseEvent) => {
        this.show(event, true);
      });
    } else {
      this.triggerEvent.forEach((ev) => {
        target.removeEventListener(ev, (event: MouseEvent) => {
          this.show(event, false);
        });
      });
    }
  }

  disconnectedCallback() {
    if (this.global) {
      this.unbindListeners('body');
    } else if (!isNullOrUndefined(this.target)) {
      this.unbindListeners(this.target);
    }
  }

  render() {
    return (
      <div
        ref={(el) => (this.containerRef = el as HTMLInputElement)}
        class={{
          'mx-context-container border border-solid text-primary border-neutral-least-subtle bg-primary': true,
          'mx-global-menu': this.isGlobalMenu,
          [this.styleClass]: !isNullOrUndefined(this.styleClass)
        }}>
        <div class='mx-sub-menu'>
          <ul class='mx-context-sub-menu'>
            {this.model &&
              this.model.map((child: ContextMenuItem) => (
                <Fragment>
                  {!child?.separator && child?.visible !== false && (
                    <li
                      class={{
                        'mx-context-menu-item hover:bg-quaternary': true,
                        'disabled-item bg-quaternary text-tertiary': child.disabled,
                        [child.styleClass]: !isNullOrUndefined(child.styleClass)
                      }}
                      id={child.id}
                      title={child.title}
                      tabindex={this.getTabIndex(child)}
                      onClick={($event) => this.triggerItemCommand($event, child)}
                      onKeyPress={($event) => this.triggerItemCommand($event, child)}
                      style={{ ...child.style }}>
                      {child.icon &&
                        h(child.icon, {
                          class: { 'mx-context-icon': true },
                          'icon-type': child.icon,
                          'icon-size': 's'
                        })}
                      <span class='ui-menuitem-text'>{child.label}</span>
                    </li>
                  )}
                  {child?.separator && child?.visible !== false && (
                    <li 
                      class='mx-context-menu-separator border border-solid border-neutral-least-subtle' 
                      data-id={child.id}></li>
                  )}
                </Fragment>
              ))}
          </ul>
        </div>
      </div>
    );
  }
}
